mapper.select:
select t1.comp_id , t1.std_eq_id , t4.inspection_cycle , (select check_dt from esg.tb_safety_inspection_log where write_year = #{writeYear} and comp_id = #{compId} and std_eq_id = t2.std_eq_id and equipment_id = t3.equipment_id order by check_dt desc limit 1 ) , t5.minor_nm as inspection_cycle_nm , t2.std_eq_nm , t3.equipment_id , t3.equipment_nm , t1.use_yn , case when t4.inspection_cycle = '0001' then case when exists ( select 1 from esg.tb_safety_inspection_log log left join esg.tb_safety_inspection_log_detail log_detail on log.write_year = log_detail.write_year and log.doc_no = log_detail.doc_no and log.check_dt = log_detail.check_dt where log.comp_id = t1.comp_id and log.std_eq_id = t1.std_eq_id and log.equipment_id = t3.equipment_id and log.check_dt = to_char(current_date, 'yyyymmdd') and (log_detail.acceptable_yn = 'Y' or log_detail.non_compliant_yn = 'Y') ) and not exists ( select 1 from esg.tb_safety_inspection_log log left join esg.tb_safety_inspection_log_detail log_detail on log.write_year = log_detail.write_year and log.doc_no = log_detail.doc_no and log.check_dt = log_detail.check_dt where log.comp_id = t1.comp_id and log.std_eq_id = t1.std_eq_id and log.equipment_id = t3.equipment_id and log.check_dt = to_char(current_date, 'yyyymmdd') and log_detail.acceptable_yn = 'N' and log_detail.non_compliant_yn = 'N' ) then 'Y' else 'N' end when t4.inspection_cycle = '0002' then case when exists ( select 1 from esg.tb_safety_inspection_log log left join esg.tb_safety_inspection_log_detail log_detail on log.write_year = log_detail.write_year and log.doc_no = log_detail.doc_no and log.check_dt = log_detail.check_dt where log.comp_id = t1.comp_id and log.std_eq_id = t1.std_eq_id and log.equipment_id = t3.equipment_id and to_char(to_date(log.check_dt, 'yyyymmdd'), 'yyyymm') = to_char(current_date, 'yyyymm') and (log_detail.acceptable_yn = 'Y' or log_detail.non_compliant_yn = 'Y') ) and not exists ( select 1 from esg.tb_safety_inspection_log log left join esg.tb_safety_inspection_log_detail log_detail on log.write_year = log_detail.write_year and log.doc_no = log_detail.doc_no and log.check_dt = log_detail.check_dt where log.comp_id = t1.comp_id and log.std_eq_id = t1.std_eq_id and log.equipment_id = t3.equipment_id and to_char(to_date(log.check_dt, 'yyyymmdd'), 'yyyymm') = to_char(current_date, 'yyyymm') and log_detail.acceptable_yn = 'N' and log_detail.non_compliant_yn = 'N' ) then 'Y' else 'N' end else 'N' end as inspection_yn from esg.tb_safety_checklist t1 left join esg.tb_dataset_typeofequipment t2 on t1.comp_id = t2.comp_id and t1.std_eq_id = t2.std_eq_id left join esg.tb_equipment_info t3 on t1.comp_id = t3.comp_id and t2.std_eq_id = t3.std_eq_id and t3.use_yn = 'Y' left join ( select distinct on (write_year, std_eq_id) * from esg.tb_safety_checklist_history where comp_id = #{compId} order by write_year, std_eq_id, created_at desc ) t4 on t1.write_year = t4.write_year and t1.std_eq_id = t4.std_eq_id left join esg.tb_common_d t5 on t5.major_cd = 'C0046' and t1.inspection_cycle = t5.minor_cd
left join esg.tb_safety_checkList_hr t6 on t3.equipment_id = t6.equipment_id
where t1.comp_id = #{compId}
and t6.hr_id = #{hrId}
order by t1.std_eq_id desc, t3.equipment_id desc,t1.use_yn desc

SELECT tsil.*, tsil.check_dt, tdt.std_eq_nm, tei.equipment_nm, thi.hr_nm, tsc.title, tcd.minor_nm as inspectionCycleNm, tsil.check_start || ' ~ ' || tsil.check_end AS check_time, toi.orgn_nm as hr_orgn_nm, tai.signature FROM esg.tb_safety_inspection_log tsil LEFT JOIN esg.tb_safety_checklist tsc ON tsil.write_year = tsc.write_year AND tsil.std_eq_id = tsc.std_eq_id AND tsil.comp_id = tsc.comp_id LEFT JOIN esg.tb_dataset_typeofequipment tdt ON tdt.std_eq_id = tsil.std_eq_id AND tdt.comp_id = tsil.comp_id LEFT JOIN esg.tb_equipment_info tei ON tei.equipment_id = tsil.equipment_id LEFT JOIN esg.tb_approval_info tai ON tai.target_type = tsil.doc_type AND tai.target_id = tsil.write_year||tsil.doc_no AND tai.type = 'inspector' LEFT JOIN esg.tb_hr_info thi on thi.hr_id = tai.hr_id LEFT JOIN esg.tb_orgn_info toi on toi.orgn_id = thi.orgn_id LEFT JOIN esg.tb_common_d tcd ON tcd.major_cd ='C0046' AND tcd.minor_cd = tsc.inspection_cycle WHERE tsil.comp_id = #{compId}
AND tsil.write_year = #{writeYear} AND tsil.doc_no = #{docNo}
AND tsil.std_eq_id = #{stdEqId} AND tsil.equipment_id= #{equipmentId} AND tsil.check_dt = #{checkDt}

select
    t1.check_dt
from esg.tb_safety_inspection_log t1
where t1.std_eq_id = #{stdEqId}
    and t1.equipment_id = #{equipmentId}
    and t1.comp_id = #{compId}
    and t1.check_dt between #{writeYear}||'0101' and #{writeYear}||'1231'
order by t1.check_dt desc

mapper.update:
UPDATE esg.tb_safety_inspection_log
SET
    check_start = #{checkStart},
    check_end = #{checkEnd},
    setup_location = #{setupLocation},
    mf_spec = #{mfSpec},
    orgn_nm = #{orgnNm},
    non_compliance_action = #{nonComplianceAction},
    use_yn = #{useYn},
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE comp_id = #{compId}
  AND write_year = #{writeYear}
  AND doc_no = #{docNo}
  AND doc_type = #{docType}
  AND check_dt = #{checkDt}

UPDATE esg.tb_safety_inspection_log_detail
SET
    acceptable_yn = #{acceptableYn},
    non_compliant_yn = #{nonCompliantYn},
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE 1 = 1
  AND write_year = #{writeYear}
  AND doc_no = #{docNo}
  AND doc_type = #{docType}
  AND doc_seq = #{docSeq}
  AND check_dt = #{checkDt}

